+    #[test]
+    fn test_clean_memory_prepared_count_star_skips_read_boundary_after_explicit_writes() {
+        let _profile_guard = super::pager_routing_tests::StatementReuseHotPathProfileGuard::new();
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute(
+            "CREATE TABLE clean_memory_count (
+                id INTEGER PRIMARY KEY,
+                name TEXT NOT NULL,
+                score INTEGER NOT NULL
+            );",
+        )
+        .unwrap();
+        conn.execute("BEGIN").unwrap();
+        for id in 0..32_i64 {
+            conn.execute_with_params(
+                "INSERT INTO clean_memory_count VALUES (?1, ('name_' || ?1), (?1 * 7));",
+                &[SqliteValue::Integer(id)],
+            )
+            .unwrap();
+        }
+        conn.execute("COMMIT").unwrap();
+        conn.execute("CREATE INDEX idx_clean_memory_count_name ON clean_memory_count(name);")
+            .unwrap();
+        assert!(
+            conn.retained_autocommit_txn.borrow().is_none(),
+            "explicit setup plus index creation should leave a clean autocommit memory image"
+        );
+
+        let stmt = conn
+            .prepare("SELECT COUNT(*) FROM clean_memory_count;")
+            .unwrap();
+        assert!(matches!(
+            stmt.prepared_query_fast_path.as_ref(),
+            Some(&super::PreparedQueryFastPath::SimpleCountStar { .. })
+        ));
+
+        super::reset_hot_path_profile();
+        let row = stmt.query_row().unwrap();
+        assert_eq!(row.get(0), Some(&SqliteValue::Integer(32)));
+        let profile = super::hot_path_profile_snapshot();
+        assert_eq!(profile.direct_count_star_query_row_hits, 1);
+        assert_eq!(
+            profile.begin_setup_time_ns, 0,
+            "clean memory COUNT(*) query_row should not open an autocommit read transaction: {profile:?}"
+        );
+
+        super::reset_hot_path_profile();
+        let rows = stmt.query().unwrap();
+        assert_eq!(rows.len(), 1);
+        assert_eq!(rows[0].get(0), Some(&SqliteValue::Integer(32)));
+        let profile = super::hot_path_profile_snapshot();
+        assert_eq!(
+            profile.begin_setup_time_ns, 0,
+            "clean memory COUNT(*) query should not open an autocommit read transaction: {profile:?}"
+        );
+        assert_eq!(
+            profile.parser.slow_path_executions, 0,
+            "clean memory COUNT(*) should remain on the fast path: {profile:?}"
+        );
+    }
